import re
from typing import Any
from pydantic import BaseModel


class ValidationErrorDetail(BaseModel):
    loc: list[str]
    msg: str
    type: str


class HTTPValidationError(BaseModel):
    detail: list[ValidationErrorDetail]


class ErrorResponse(BaseModel):
    status_code: int
    detail: str | list


class RequestValidator:
    """Validates request data against configurable rules."""

    def __init__(self):
        self.rules: dict[str, list[tuple[str, Any, str]]] = {}

    def add_rule(self, field: str, rule_type: str, value: Any, message: str) -> None:
        if field not in self.rules:
            self.rules[field] = []
        self.rules[field].append((rule_type, value, message))

    def validate(self, data: dict) -> tuple[bool, list[ValidationErrorDetail]]:
        errors = []
        for field, field_rules in self.rules.items():
            is_required = any(rt == "required" for rt, _, _ in field_rules)
            present = field in data

            if not present:
                if is_required:
                    msg = next(m for rt, _, m in field_rules if rt == "required")
                    errors.append(ValidationErrorDetail(loc=["body", field], msg=msg, type="missing"))
                continue

            val = data[field]

            for rule_type, rule_value, message in field_rules:
                if rule_type == "required":
                    continue
                elif rule_type == "type":
                    if not isinstance(val, rule_value):
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="type_error"))
                elif rule_type == "min_length":
                    if isinstance(val, str) and len(val) < rule_value:
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="value_error"))
                elif rule_type == "max_length":
                    if isinstance(val, str) and len(val) > rule_value:
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="value_error"))
                elif rule_type == "min_value":
                    if isinstance(val, (int, float)) and val < rule_value:
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="value_error"))
                elif rule_type == "max_value":
                    if isinstance(val, (int, float)) and val > rule_value:
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="value_error"))
                elif rule_type == "pattern":
                    if isinstance(val, str) and not re.match(rule_value, val):
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="value_error"))
                elif rule_type == "choices":
                    if val not in rule_value:
                        errors.append(ValidationErrorDetail(loc=["body", field], msg=message, type="value_error"))

        return (len(errors) == 0, errors)


def build_422_response(errors: list[ValidationErrorDetail]) -> ErrorResponse:
    """Build a 422 ErrorResponse from validation errors."""
    return ErrorResponse(
        status_code=422,
        detail=[e.model_dump() for e in errors]
    )


def validate_create_user(data: dict) -> tuple[bool, ErrorResponse | dict]:
    """Validate user creation data."""
    v = RequestValidator()
    v.add_rule("username", "required", True, "Field required")
    v.add_rule("username", "min_length", 3, "String should have at least 3 characters")
    v.add_rule("username", "max_length", 20, "String should have at most 20 characters")
    v.add_rule("username", "pattern", r"^[a-zA-Z][a-zA-Z0-9_]*$", "String does not match pattern")
    v.add_rule("email", "required", True, "Field required")
    v.add_rule("email", "pattern", r"^[^@\s]+@[^@\s]+\.[^@\s]+$", "Invalid email format")
    v.add_rule("age", "required", True, "Field required")
    v.add_rule("age", "type", int, "Input should be a valid integer")
    v.add_rule("age", "min_value", 0, "Input should be greater than or equal to 0")
    v.add_rule("age", "max_value", 150, "Input should be less than or equal to 150")
    v.add_rule("role", "choices", ["user", "admin", "moderator"], "Invalid choice")

    ok, errors = v.validate(data)
    if not ok:
        return (False, build_422_response(errors))
    return (True, dict(data))


def validate_update_product(data: dict) -> tuple[bool, ErrorResponse | dict]:
    """Validate product update data (partial update)."""
    v = RequestValidator()
    v.add_rule("name", "min_length", 1, "String should have at least 1 character")
    v.add_rule("name", "max_length", 100, "String should have at most 100 characters")
    v.add_rule("price", "type", (int, float), "Input should be a valid number")
    v.add_rule("price", "min_value", 0, "Input should be greater than or equal to 0")
    v.add_rule("category", "choices", ["electronics", "clothing", "food", "other"], "Invalid choice")

    ok, errors = v.validate(data)
    if not ok:
        return (False, build_422_response(errors))
    return (True, {k: v for k, v in data.items() if k in data})
